FUNCTION NFA(input) {
  // Initialize the NFA
  // Read the input symbol
  // Move to the next state
  // If the input symbol is epsilon, move to the next state without consuming the input
}

public class DFA {
  private int[][] transitionTable;
  private int currentState;
  public DFA(int[][] transitionTable) {
    this.transitionTable = transitionTable;
    this.currentState = 0;
  }
  public boolean accept(String input) {
    for (int i = 0; i < input.length(); i++) {
      int symbol = input.charAt(i);
      currentState = transitionTable[currentState][symbol];
    }
    return currentState == 1;
  }
}
